"use strict";

var domApp = document.querySelector(".app");
var domTime = document.querySelector(".time");
var domDate = document.querySelector(".date");
var domCnDate = document.querySelector(".cn-date");
var domWeather = document.querySelector(".weather"); // 天气DOM引用

function geturl(url) {
    var arr = url.split("?");
    if (!arr[1]) { return {} }
    var res = arr[1].split("&");
    var items = {};
    for (var i = 0; i < res.length; i++) {
        var a = res[i].split("=");
        items[a[0]] = a[1]
    }
    return items
}

function formatDate(date) {
    var fmt = arguments.length > 1 && arguments[1] !== undefined ? arguments[1] : "yyyy-MM-dd";
    if (!date) { return "" }
    if (typeof date === "number" || typeof date === "string") {
        date = new Date(Number(date))
    }
    var o = {
        "M+": date.getMonth() + 1,
        "d+": date.getDate(),
        "h+": date.getHours(),
        "m+": date.getMinutes(),
        "s+": date.getSeconds(),
        "q+": Math.floor((date.getMonth() + 3) / 3),
        S: date.getMilliseconds()
    };
    if (/(y+)/.test(fmt)) fmt = fmt.replace(RegExp.$1, "".concat(date.getFullYear()).substr(4 - RegExp.$1.length));
    for (var k in o)
    if (new RegExp("(".concat(k, ")")).test(fmt)) fmt = fmt.replace(RegExp.$1, RegExp.$1.length === 1 ? o[k] : "00".concat(o[k]).substr("".concat(o[k]).length));
    return fmt
}

// 简化版获取天气函数
function fetchWeather() {
    var openWeatherApiKey = '13e786b2255800d48474a6fdbcd071dc';
    var city = urlQuery.city || "Shanghai"; // 可通过URL参数修改城市
    var unit = "metric";
    var lang = urlQuery.l === "en" ? "en" : "zh_cn";

    // 使用GET请求而不是fetch，解决Kindle兼容性问题
    var xhr = new XMLHttpRequest();
    var url = "https://api.openweathermap.org/data/2.5/weather?q=" + city + "&appid=" + openWeatherApiKey + "&units=" + unit + "&lang=" + lang;

    xhr.onreadystatechange = function() {
        if (xhr.readyState === 4) {
            if (xhr.status === 200) {
                try {
                    var data = JSON.parse(xhr.responseText);
                    updateWeather(data);
                } catch (e) {
                    domWeather.innerHTML = "天气数据解析错误";
                }
            } else {
                domWeather.innerHTML = urlQuery.l === "en" ? "Weather unavailable" : "无法获取天气";
            }
        }
    };

    xhr.onerror = function() {
        domWeather.innerHTML = urlQuery.l === "en" ? "Network error" : "网络错误";
    };

    try {
        xhr.open("GET", url, true);
        xhr.send();
    } catch (e) {
        domWeather.innerHTML = urlQuery.l === "en" ? "Request failed" : "请求失败";
    }
}

// 极简天气显示
function updateWeather(data) {
    if (!data || !data.main) {
        domWeather.innerHTML = urlQuery.l === "en" ? "No data" : "无数据";
        return;
    }

    var temp = Math.round(data.main.temp);
    var description = data.weather[0].description;

    // 仅显示温度和天气描述
    var weatherText = urlQuery.l === "en" ?
        `${temp}°C ${description}` :
        `${temp}°C ${description}`;

    domWeather.innerHTML = weatherText;
}

function render() {
    var time = new Date();
    var len = time.getTime();
    var offset = time.getTimezoneOffset() * 60000;
    var utcTime = len + offset;
    var date = new Date(utcTime + 3600000 * 8);
    var lunar = calendar.solar2lunar(date.getUTCFullYear(), date.getUTCMonth() + 1, date.getUTCDate());
    var dateText = "".concat(formatDate(date, "yyyy.M.d"), " ").concat(urlQuery.l == "en" ? ["SUN", "MON", "TUES", "WED", "THUR", "FRI", "SAT"][date.getDay()] : "星期" + ["日", "一", "二", "三", "四", "五", "六"][date.getDay()]);
    var timeText = "".concat(date.getHours(), ":").concat(date.getMinutes() < 10 ? '0' + date.getMinutes() : date.getMinutes());
    var cnDateText = "".concat(lunar.IMonthCn).concat(lunar.IDayCn, " ").concat(lunar.Animal, "\u5E74");
    if (domDate.innerHTML != dateText) domDate.innerHTML = dateText;
    if (domTime.innerHTML != timeText) domTime.innerHTML = timeText;
    if (domCnDate.innerHTML != cnDateText) domCnDate.innerHTML = cnDateText;
}

var urlQuery = geturl(location.href);
var config = {
    fontSize: +(urlQuery.fs || 7),
    rotate: urlQuery.r,
    lang: urlQuery.l
};

domTime.style.fontSize = config.fontSize + "rem";
domDate.style.fontSize = config.fontSize / 2.5 + "rem";
domCnDate.style.fontSize = config.fontSize / 4 + "rem";
domWeather.style.fontSize = config.fontSize / 4 + "rem";

domApp.style.cssText = "-webkit-transform: rotate(".concat(config.rotate || 0, "deg) translate3d(-50%,-50%,0)");

render();
setInterval(function() {
    render()
}, 1000);

// 获取天气数据（延迟3秒再获取，确保页面已完全加载）
setTimeout(function() {
    try {
        fetchWeather();
    } catch (e) {
        domWeather.innerHTML = "天气初始化失败";
    }
}, 3000);

// 每3小时更新一次天气（减少API调用频率）
setInterval(function() {
    try {
        fetchWeather();
    } catch (e) {
        // 忽略错误
    }
}, 10800000);